#[no_mangle] pub unsafe extern "C" fn nelisp_eval_call(form: *const Sexp, env: *mut std::ffi::c_void, out: *mut Sexp) -> i64 { let r = &mut *(env as *mut Env); let res = eval(&*form, r); eval_stash_err(r, res, out) } #[no_mangle] pub unsafe extern "C" fn nelisp_eval_call_with_err(form: *const Sexp, env: *mut std::ffi::c_void, out: *mut Sexp, err_out: *mut Sexp) -> i64 { let r = &mut *(env as *mut Env); match eval(&*form, r) { Ok(v) => { std::ptr::write(out, v); 0 } Err(e) => { std::ptr::write(err_out, e.signal_data()); 1 } } } #[no_mangle] pub unsafe extern "C" fn nelisp_apply_function(func: *const Sexp, args_list: *const Sexp, env: *mut std::ffi::c_void, out: *mut Sexp) -> i64 { let r = &mut *(env as *mut Env); let res = apply_function(&*func, &list_elements(&*args_list).unwrap_or_default(), r); eval_stash_err(r, res, out) } pub(crate) fn consume_stashed_error(env: &mut Env, fallback: &str) -> EvalError { let Ok(Sexp::Cons(b)) = env.lookup_value("nelisp--last-signal-data") else { return EvalError::internal(fallback); }; match &b.car { Sexp::Symbol(s) if s == "quit" => EvalError::Quit, Sexp::Symbol(t) => EvalError::Generic(t.clone(), b.cdr.clone()), _ => EvalError::internal(fallback) } } pub unsafe fn nlrc_payload_drop<T>(ptr: *mut std::ffi::c_void) { std::ptr::drop_in_place(ptr as *mut T); } macro_rules! drop_inner_extern { ($name:ident, $ty:path) => { #[no_mangle] pub unsafe extern "C" fn $name(box_ptr: *mut i64) -> i64 { <$ty>::DROP_FN(box_ptr as *mut std::ffi::c_void); 1 } }; } drop_inner_extern!(nl_consbox_drop_inner, crate::eval::nlboxes::NlConsBox); drop_inner_extern!(nl_vector_drop_inner, crate::eval::nlboxes::NlVector); drop_inner_extern!(nl_cell_drop_inner, crate::eval::nlboxes::NlCell); drop_inner_extern!(nl_record_drop_inner, crate::eval::nlboxes::NlRecord); drop_inner_extern!(nl_str_drop_inner, crate::eval::nlboxes::NlStr); drop_inner_extern!(nl_boolvector_drop_inner, crate::eval::nlboxes::NlBoolVector); drop_inner_extern!(nl_chartable_drop_inner, crate::eval::nlboxes::NlCharTable); fn nl_layout(s: i64, a: i64) -> Option<Layout> { (s>0&&a>0).then(||Layout::from_size_align(s as usize,a as usize).ok()).flatten() } #[no_mangle] pub unsafe extern "C" fn nl_alloc_bytes(size: i64, align: i64) -> *mut u8 { nl_layout(size,align).map_or(std::ptr::null_mut(),|l|unsafe{alloc::alloc(l)}) } #[no_mangle] pub unsafe extern "C" fn nl_dealloc_bytes(ptr: *mut u8, size: i64, align: i64) { if !ptr.is_null(){if let Some(l)=nl_layout(size,align){unsafe{alloc::dealloc(ptr,l)};}} } static QUIT_FLAG: AtomicI64 = AtomicI64::new(0); #[cfg(unix)] static SIGINT_INSTALLED: AtomicBool = AtomicBool::new(false); #[no_mangle] pub extern "C" fn nl_quit_flag_ptr() -> *mut i64 { QUIT_FLAG.as_ptr() } pub fn take_quit_flag() -> bool { QUIT_FLAG.swap(0, Ordering::SeqCst) != 0 } #[cfg(unix)] pub fn install_sigint_handler() { static ONCE: Once = Once::new(); ONCE.call_once(|| unsafe { extern "C" fn handler(_: libc::c_int) { QUIT_FLAG.store(1, Ordering::SeqCst); } let mut sa: libc::sigaction = std::mem::zeroed(); sa.sa_sigaction = handler as *const () as usize; libc::sigemptyset(&mut sa.sa_mask); sa.sa_flags = libc::SA_RESTART; libc::sigaction(libc::SIGINT, &sa, std::ptr::null_mut()); SIGINT_INSTALLED.store(true, Ordering::SeqCst); }); } #[cfg(not(unix))] pub fn install_sigint_handler() {} #[cfg(unix)] pub fn sigint_handler_installed_p() -> bool { SIGINT_INSTALLED.load(Ordering::SeqCst) } #[cfg(not(unix))] pub fn sigint_handler_installed_p() -> bool { false } pub(crate) fn bi_globals_op(args: &[Sexp], env: &mut Env) -> Result<Sexp, EvalError> { let sym = |s: &Sexp| match s { Sexp::Symbol(n) => Ok(n.clone()), o => Err(EvalError::wrong_type("symbolp", o.clone())) }; let arity = |n: usize| EvalError::wrong_arity("nelisp--env-globals-op", n.to_string(), args.len()); let op = sym(args.first().ok_or_else(|| arity(1))?)?; let (exp, op) = match op.as_str() { "capture-lexical" => (1, op.as_str()), "set-value"|"set-function"|"set-constant" => (3, op.as_str()), _ => (2, op.as_str()) }; if args.len() != exp { return Err(arity(exp)); } if op == "capture-lexical" { return Ok(env.capture_lexical()); } let name = sym(&args[1])?; let (mut result, mut scratch) = (Sexp::Nil, Sexp::Nil); let rc = if op == "set-value" || op == "set-function" || op == "set-constant" { let flag = if matches!(args[2], Sexp::Nil) { Sexp::Nil } else { Sexp::T }; let sc = crate::elisp_cc_spike::build_or_insert_scratch_vec(if op == "set-value" { args[2].clone() } else { env.unbound_marker.clone() }, if op == "set-function" { args[2].clone() } else { env.unbound_marker.clone() }, Sexp::Nil, if op == "set-constant" { flag } else { Sexp::Nil }); unsafe { crate::elisp_cc_spike::env_shim_set_op(&args[0], &env.globals_record, &args[1], &sc, &mut result, 0) } } else { unsafe { crate::elisp_cc_spike::env_shim_op(&args[0], &env.globals_record, &args[1], &env.unbound_marker, &mut result, &mut scratch) } }; match rc { 1 => Ok(result), 0 => Err(EvalError::unbound_var(name)), -1 => Err(EvalError::unbound_fn(name)), _ => Err(EvalError::internal(format!("nelisp--env-globals-op: unknown OP `{op}'"))) } } #[cfg(test)] mod nlrc_tests { use super::*; #[test] fn alloc_round_trip() { let p=unsafe{nl_alloc_bytes(64,8)}; assert!(!p.is_null()); unsafe{nl_dealloc_bytes(p,64,8)} } #[test] fn alloc_bad() { for(s,a)in[(32,3),(0,8),(-1,8),(32,0)]{assert!(unsafe{nl_alloc_bytes(s,a)}.is_null());} } #[test] fn alloc_null_aligned() { unsafe{nl_dealloc_bytes(std::ptr::null_mut(),32,8)}; let p=unsafe{nl_alloc_bytes(128,16)}; assert!(!p.is_null()&&p as usize&0xF==0); unsafe{nl_dealloc_bytes(p,128,16)} } } #[cfg(test)] mod env_shim_tests { use super::*; use crate::eval::{eval_str, eval_str_all}; macro_rules! ok { ($e:expr) => { eval_str_all($e).unwrap() }; ($s:literal => $p:pat) => { assert!(matches!(eval_str($s).unwrap(), $p)) }; ($s:literal => all => $p:pat) => { assert!(matches!(eval_str_all($s).unwrap(), $p)) }; } #[test] fn set_get_value() { assert!(matches!(ok!("(nelisp--env-globals-set-value 'doc-86-3a-foo 42) (nelisp--env-globals-get-value 'doc-86-3a-foo)"), Sexp::Int(42))); } #[test] fn get_unbound_errors() { assert!(eval_str("(nelisp--env-globals-get-value 'doc-86-3a-undef-symbol)").is_err()); } #[test] fn is_bound_reflects_set() { ok!("(nelisp--env-globals-is-bound 'doc-86-3a-bar)" => Sexp::Nil); ok!("(nelisp--env-globals-set-value 'doc-86-3a-bar 7) (nelisp--env-globals-is-bound 'doc-86-3a-bar)" => all => Sexp::T); } #[test] fn set_function_round_trip() { ok!("(nelisp--env-globals-set-function 'doc-86-3a-fn (nelisp--env-globals-get-function 'eq)) (nelisp--env-globals-is-fbound 'doc-86-3a-fn)" => all => Sexp::T); ok!("(nelisp--env-globals-set-function 'doc-86-3a-fn2 (nelisp--env-globals-get-function 'eq)) (nelisp--env-globals-clear-function 'doc-86-3a-fn2) (nelisp--env-globals-is-fbound 'doc-86-3a-fn2)" => all => Sexp::Nil); } #[test] fn constant_flag_round_trip() { ok!("(nelisp--env-globals-is-constant 'doc-86-3a-cflag)" => Sexp::Nil); ok!("(nelisp--env-globals-set-constant 'doc-86-3a-cflag t) (nelisp--env-globals-is-constant 'doc-86-3a-cflag)" => all => Sexp::T); } #[test] fn capture_and_clear() { ok!("(nelisp--env-globals-op 'capture-lexical)" => Sexp::Nil); ok!("(nelisp--env-globals-set-value 'doc-86-3a-baz 1) (nelisp--env-globals-clear-value 'doc-86-3a-baz) (nelisp--env-globals-is-bound 'doc-86-3a-baz)" => all => Sexp::Nil); } }
